// Ship a custom drafter with the request. Generator verifies drafts.
struct PromptLookup {
    pool: Vec<u32>,
    cursor: u32,
    ngram_n: usize,
    draft_len: usize,
}

impl Speculator for PromptLookup {
    fn draft(&mut self) -> (Vec<u32>, Vec<u32>) {
        let drafts = lookup_suffix_match(&self.pool, self.ngram_n, self.draft_len);
        let positions = (self.cursor..self.cursor + drafts.len() as u32).collect();
        (drafts, positions)
    }

    fn accept(&mut self, accepted: &[u32]) {
        // accepted[0] is the free model token; the rest are verified drafts.
        self.pool.extend_from_slice(accepted);
        self.cursor += accepted.len() as u32;
    }
}

let drafter = PromptLookup::new(prompt_tokens, ngram_n, draft_len, cursor);
let mut generator = ctx.generate(Sampler::Argmax)
    .max_tokens(max_tokens)
    .stop(&chat::stop_tokens(&model))
    .speculator(drafter);

while let Some(step) = generator.next()? {
    let out = step.execute().await?;      // [free token, accepted drafts...]
    stream_tokens(&out.tokens)?;
}
